import React, { useEffect, useState } from 'react';

const Navbar = () => {
  const [menuOpen, setMenuOpen] = useState(false);

  useEffect(() => {
    const links = document.querySelectorAll('.navmenu a');

    links.forEach(link => {
      link.addEventListener('click', (event) => {
        event.preventDefault();
        const targetId = link.getAttribute('href').substring(1);
        const targetElement = document.getElementById(targetId);

        if (targetElement) {
          window.scrollTo({
            top: targetElement.offsetTop, // Adjust for fixed navbar height
            behavior: 'smooth'
          });
        }

        // Close menu after clicking in mobile view
        setMenuOpen(false);
      });
    });

  }, []);

  return (
    <header id="header" className="header d-flex flex-column justify-content-center">
      {/* Toggle Button for Mobile */}
      <i className="header-toggle d-xl-none bi bi-list" onClick={() => setMenuOpen(!menuOpen)}></i>

      {/* Menu */}
      <nav id="navmenu" className={`navmenu ${menuOpen ? 'open' : ''}`}>
        <ul>
          <li><a href="#hero"><i className="bi bi-house navicon"></i><span>Home</span></a></li>
          <li><a href="#about"><i className="bi bi-person navicon"></i><span>About</span></a></li>
          <li><a href="#skills"><i className="bi bi-lightbulb navicon"></i><span>Skills</span></a></li>
          <li><a href="#resume"><i className="bi bi-file-earmark-text navicon"></i><span>Resume</span></a></li>
          <li><a href="#portfolio"><i className="bi bi-images navicon"></i><span>Portfolio</span></a></li>
          <li><a href="#services"><i className="bi bi-hdd-stack navicon"></i><span>Services</span></a></li>
          <li><a href="#contact"><i className="bi bi-envelope navicon"></i><span>Contact</span></a></li>
        </ul>
      </nav>
    </header>
  );
};

export default Navbar;
